'use client';
import { useParams } from 'next/navigation';
import EventDetails from '@/components/ui/eventDetials';
import { useAuth } from '@/context/AuthContext';
import { useEffect, useState } from 'react';
import { EventCategory } from '@/types';
import { fetchEvent } from '@/api/events/event';
import NotFound from '@/components/ui/NotFound';
import { useToast } from '@/hooks/use-toast';
import { Loading } from '@/components/ui/Loading';

const EventDetailsPage = () => {
  const params = useParams();
  const { toast } = useToast();
  const { token, userRole } = useAuth();
  const [event, setEvent] = useState<EventCategory | null>(null);
  const [loading, setLoading] = useState(false);
  const eventId = params.eventId as string;

  useEffect(() => {
    if (token) {
      fetchEvent(setLoading, token, eventId,undefined, toast).then((data) => {
        setEvent(data);
      });
    }
  }, [token, eventId]);
  if (loading) {
    return <Loading />;
  }
  return (
    <>
      {event ? (
        <EventDetails
          event={event}
          userRole={userRole}
        />
      ) : (
        <NotFound message='Event not found' />
      )}
    </>
  );
};

export default EventDetailsPage;
